head.script:
(function(){
  const XHTML_NS="http://www.w3.org/1999/xhtml";
  const root=document.querySelector("foreignObject").firstElementChild;
  const head=root.querySelector("head");
  const body=root.querySelector("body");

  const ce=document.createElement.bind(document);
  const cens=document.createElementNS.bind(document);

  Object.defineProperty(document,"head",{get(){return head}});
  Object.defineProperty(document,"body",{get(){return body}});
  Object.defineProperty(document,"documentElement",{get(){return root}});

  document.createElement=function(tag,opts){
    return typeof tag==="string" ? cens(XHTML_NS,tag,opts) : ce(tag,opts);
  };

  document.createElementNS=function(ns,name,opts){
    return (!ns||ns===XHTML_NS) ? cens(XHTML_NS,name,opts) : cens(ns,name,opts);
  };
})();

body.script:
(async function(){

  const SOURCES = [
    "https://raw.githubusercontent.com/Darkdragonzxs/zd-pages/main/zodiac.html",
    "https://cdn.jsdelivr.net/gh/Darkdragonzxs/zd-pages@main/zodiac.html",
    "https://raw.githack.com/Darkdragonzxs/zd-pages/main/zodiac.html"
  ];

  let html = null;

  for (const u of SOURCES) {
    try {
      const r = await fetch(u);
      if (!r.ok) continue;
      html = await r.text();
      break;
    } catch(e){}
  }

  if (!html) {
    document.body.textContent = "failed to load";
    return;
  }

  const CLOSE = "<" + "/script>";
  html = html.split(CLOSE).join("");

  document.open();
  document.write(html);
  document.close();

})();
